<style>
    .sentence-builder-area {
        min-height: 120px;
        border: 3px dashed #3498db;
        border-radius: 20px;
        background-color: #f8f9fa;
    }

    .min-height-100 {
        min-height: 100px;
    }

    .word-card {
        font-size: 1.5rem;
        padding: 1rem 2rem;
        border-radius: 50px;
        margin: 5px;
        transition: all 0.3s ease;
        box-shadow: 0 5px 15px rgba(0,0,0,0.1);
        cursor: pointer;
    }

        .word-card:hover {
            transform: translateY(-3px);
            box-shadow: 0 8px 20px rgba(0,0,0,0.2);
        }

        .word-card:active {
